package com.aadil.jobtracker.UserController;import com.aadil.jobtracker.UserRepository.SortDirection;import com.aadil.jobtracker.UserRepository.UserRepository;import com.aadil.jobtracker.UserRepository.UserSortField;import com.aadil.jobtracker.Validation.UserResponseDTO;import com.aadil.jobtracker.Validation.UserRequestDTO;import com.aadil.jobtracker.UserService.UserServiceImp;import com.aadil.jobtracker.responses.APIResponse;import jakarta.validation.Valid;import jakarta.validation.constraints.Max;import jakarta.validation.constraints.Min;import org.jetbrains.annotations.NotNull;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.data.domain.Page;import org.springframework.http.ResponseEntity;import org.springframework.validation.annotation.Validated;import org.springframework.web.bind.annotation.*;import java.util.List;import java.util.Optional;@RestController@RequestMapping("/users")@Validatedpublic class UserController {    private final UserServiceImp userService;    public UserController(UserServiceImp userService) {        this.userService = userService;    }    @Autowired    UserRepository userRepository;    @PostMapping()    public ResponseEntity<@NotNull UserResponseDTO> createUser(@Valid @RequestBody UserRequestDTO dto) {        return ResponseEntity.status(201).body(userService.createUser(dto));    }    @PostMapping("/bulk")    public ResponseEntity<@NotNull List<UserResponseDTO>> createUsers(@Valid @RequestBody List<UserRequestDTO> dtos) {        return ResponseEntity.status(201).body(userService.createUsers(dtos));    }    @GetMapping("/{id}")    public ResponseEntity<@NotNull APIResponse<Optional<UserResponseDTO>>> getUser(@PathVariable Long id) {        Optional<UserResponseDTO> userResponseDTO = userService.getUser(id);        return ResponseEntity.ok(new APIResponse<>(true, userResponseDTO, "User fetched successfully"));    }    @GetMapping("/bulk")    public ResponseEntity<@NotNull List<UserResponseDTO>> getUsersById(@RequestParam List<Long> ids) {        return ResponseEntity.ok(userService.getUsersById(ids));    }    @GetMapping("/all")    public ResponseEntity<@NotNull APIResponse<Page<@NotNull UserResponseDTO>>> getAllUsers(@RequestParam(required = false) String search,        @RequestParam(defaultValue = "0") @Min(value = 0, message = "Page cannot be negative")        @Max(value = 50, message = "Pages should not exceed 50") int page,        @RequestParam(defaultValue = "0")@Min(value = 0,message = "Size should be at least 0")        @Max(value = 50,message = "Size should not exceed 50") int size,        @RequestParam (defaultValue = "ID")UserSortField userSortField,        @RequestParam(defaultValue = "ASC")SortDirection sortDirection){        Page<@NotNull UserResponseDTO> userResponseDTO=userService.getAllUsers(search,page,size,userSortField,sortDirection);        APIResponse<Page<@NotNull UserResponseDTO>> response=new APIResponse<>(true,userResponseDTO,"Every users fetched successfully");        return ResponseEntity.ok(response);    }    @PutMapping("/{id}")    public ResponseEntity<@NotNull UserResponseDTO> updateUser(@PathVariable Long id, @Valid @RequestBody UserRequestDTO dto){        return userService.updateUser(id, dto).map(ResponseEntity::ok).orElse(ResponseEntity.notFound().build());    }    @DeleteMapping("/{id}")    public ResponseEntity<@NotNull UserResponseDTO> deleteUser(@PathVariable Long id){        userService.deleteUser(id);        return ResponseEntity.noContent().build();    }    @DeleteMapping("/all")    public ResponseEntity<@NotNull UserResponseDTO> deleteAll(){        userService.deleteAll();        return ResponseEntity.noContent().build();    }    @DeleteMapping("/batch")    public ResponseEntity<@NotNull List<UserResponseDTO>>deleteAllById(@PathVariable List<Long>ids){        userService.deleteById(ids);        return ResponseEntity.noContent().build();    }}